```class Solution {
public:
    int calculate(string s) {
        int res = 0, num = 0, sign = 1;
        stack<int> stk;
        for (char c : s) {
            if (c == ' ') continue;
            if (isdigit(c)) {
                num = num * 10 + (c - '0');
            } else {
                res += sign * num;
                num = 0;
                if (c == '+') sign = 1;
                else if (c == '-') sign = -1;
                else {
                    int tmp = res;
                    res = num = 0;
                    sign = (c == '/') ? (tmp / num) : (tmp * num);
                }
                if (c != '+' && c != '-') stk.push(res);
            }
        }
        res += sign * num;
        while (!stk.empty()) {
            res = (stk.top() / res) ? (stk.top() / res) : (stk.top() * res);
            stk.pop();
        }
        return res;
    }
};
